//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
console.log("PGM : 법인별 총괄현황 (co_404_01_16b)");   

    scwin.f_FieldClear();
    scwin.dglv = DGlobalValue.TRUE;
    const codeOptions = [
        { grpCd : "CO012", compID : "lc_unit"}, 
        { grpCd : "FI054", compID : "lc_srchBookClsCd", opt :{"range" : "1"}}        
    ];
    $c.data.setCommonCode(codeOptions);
    // $p.top().ds_comCd.getAllJSON()
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search,[ed_srchCloseYm]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------

scwin.f_SetSrchDefault = function (){
    $c.gus.cfInitHidVal(tbl_search);
    ed_srchCloseYm.setValue(WebSquare.date.getCurrentServerDate("yyyyMM"));
    scwin.f_CloseYm();    
    scwin.f_GetVersion();
//    scwin.f_GetBookClsCd();
    scwin.f_SetGridFormat(ed_srchCloseYm.getValue()); 
    lc_srchBookClsCd.focus();
    chk_distYn.checkAll(false);    
}

//-------------------------------------------------------------------------
// 해당월의 실적이 있는지 여부 확인(True:테이타가 있음, False:데이타가 없음)
// 해당월의 실적이 없을경우 누적으로 해서 보여주므로 당월 마이너스 실적 나오는것을 막기위함 함수.
// As-Is 삭제 function임 ==> 주석처리되어있음
//-------------------------------------------------------------------------
//scwin.f_CountRow = function () {
//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    gr_master.initGrid();
    scwin.f_Setting();

    dma_search.set("fromDate", scwin.fromDate);
    dma_search.set("closeYm", ed_srchCloseYm.getValue());
    dma_search.set("ver", lc_version.getValue());
    dma_search.set("bookClsCd", lc_srchBookClsCd.getValue());
    dma_search.set("acctDeptCd", "1");
    dma_search.set("eisAcctDeptCd", "1");
    dma_search.set("distYn", scwin.tDist );

    $c.sbm.execute(sbm_master); 
}

//-------------------------------------------------------------------------
// 날짜셋팅 
//-------------------------------------------------------------------------
scwin.f_Setting = function () {
    scwin.imsi_date = ed_srchCloseYm.getValue() + "01";

    // 전년도 구하기
    if (scwin.imsi_date.substring(4, 6) == "01" || scwin.imsi_date.substring(4, 6) == "00") {
        dma_search.set("befCloseYm", scwin.imsi_date.substring(0, 4) + "00");
    } else {
        scwin.pre_yyyymmdd = $c.date.addMonth(scwin.imsi_date, -12);  // 전년
        dma_search.set("befCloseYm", scwin.pre_yyyymmdd.substring(0, 4) + "00");
    }
    scwin.preBef_yyyymmdd = $c.date.addMonth(scwin.imsi_date, -1); // 전월
    dma_search.set("preCloseYm", scwin.preBef_yyyymmdd.substring(0, 6));
    scwin.imsi_date1 = dma_search.get("preCloseYm") + "01";

    if (scwin.preBef_yyyymmdd.substring(4, 6) == "01" || scwin.preBef_yyyymmdd.substring(4, 6) == "00") {
        dma_search.set("preBefCloseYm", scwin.preBef_yyyymmdd.substring(0, 4) + "00");
    } else {
        dma_search.set("preBefCloseYm", scwin.preBef_yyyymmdd.substring(0, 6));
    }

}
//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function() {      
    scwin.f_SetDefaultUnit();
}

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit= function () {
    var rcnt =  dlt_commonCodeCO012.getRowCount();
    if (rcnt < 1) return;
    var index = 0;
    for (i=0; i < rcnt; i++) {  
        if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
           index = i;
           break;
       }
    }
    lc_unit.setSelectedIndex(index);    
    lc_unit.setSelectedIndex(2);        
} 


//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function () {
    dma_version.set("sysCd", "CommonEBC" );
    dma_version.set("queryId", "retrieveVersionInfo");
    dma_version.set("param1", ed_srchCloseYm.getValue().substr(0,4)+"00");

    $c.sbm.execute(sbm_version);
}


//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
//scwin.f_runExcel = function (varGrNm) {
//console.log("f_runExcel");    
//    scwin.totCnt = ds_master.getRowCount();
//    scwin.sheetTitle = '총괄표_' + ed_srchCloseYm.getValue();
//    if(ds_master.getCountRow() == 0) {
//        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
//        return;
//    }    
//    scwin.cfrm = $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
//    if (cfrm) {
//        $c.data.downloadGridViewExcel(varGrNm, scwin.sheetTitle, scwin.sheetTitle + ".xlsx", 4 + 8 + 16);
//    }      
//}
//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(ds_master.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_master.getTotalCol(); i++){
        if(gr_master.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_srchCloseYm.getValue().trim(), "####-##");
    let str1 = $c.gus.cfGetFormatStr(ed_srchCloseYm.getValue().trim(), "######");
    let str2 = lc_version.getValue(); 
    let str21 = lc_version.getText(true); 
    let str3 = lc_srchBookClsCd.getValue(); 
    let str31 = lc_srchBookClsCd.getText(true); 

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "총괄표",
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "결산년월 ["+ str +"]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 3,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "ver ["+ str21 +"], 구분 ["+ str31 +"]" ,
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 

    }]

    const options = {
        fileName: "총괄표_"+str1+".xlsx",
        //sheetName: "결산년월_"+str1+"_ver_"+str2+"_"+str3 ,
        sheetName: "총괄표",
        startRowIndex : 4,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_master, options, infoArr);
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_SetGridFormat = function (pCloseYm) {
    let v_thisMm = pCloseYm.substr(4,6) + " 당월";
    let v_cum = pCloseYm.substr(4,6) + " 누계";

    gr_master.setHeaderValue("thisMm", v_thisMm);
    gr_master.setHeaderValue("cum", v_cum);
    gr_master.initGrid();       
}
//-------------------------------------------------------------------------
// 그리드 컬럼의 금액단위를 설정한다.
//-------------------------------------------------------------------------
scwin.f_SetGridUnit = function(e) {
console.log("f_SetGridUnit");         
    scwin.sellAmt1      = 0;
    scwin.sellAmt2      = 0;
    scwin.sellAmt3      = 0;
    scwin.sellAmt4      = 0;
    scwin.sellAmt5      = 0;
    scwin.sellAmt6      = 0;
    scwin.sellAmt7      = 0;
    scwin.sellAmt8      = 0;
    scwin.sellAmt9      = 0;    
    scwin.sellAmt10     = 0;  
    scwin.sellAmt11     = 0;  

    scwin.mAcctcd = "";
    scwin.cunit = 1;
    if (lc_unit.getValue() == "02") { scwin.cunit = 1000; }
    if (lc_unit.getValue() == "03") { scwin.cunit = 1000000; }
    if (lc_unit.getValue() == "04") { scwin.cunit = 100000000; }
 	scwin.ds_master_rcnt = ds_master.getRowCount();

    for (scwin.i=0; scwin.i <= scwin.ds_master_rcnt; scwin.i++) {
        scwin.mAcctcd = ds_master.getCellData(scwin.i, "mgntAcctCd");
//        console.log(scwin.i+" : mgntAcctCdNm - "+ ds_master.getCellData(scwin.i, "mgntAcctCd")+"/"+ds_master.getCellData(scwin.i, "mgntAcctCdNm"));
        scwin.sellAmt1 = $c.num.parseInt(ds_master.getCellData(scwin.i,"yearPlanAmt"));
        scwin.sellAmt2 = $c.num.parseInt(ds_master.getCellData(scwin.i,"bfyyThisAmt"));
        scwin.sellAmt3 = $c.num.parseInt(ds_master.getCellData(scwin.i,"thisPlanAmt"));
        scwin.sellAmt4 = $c.num.parseInt(ds_master.getCellData(scwin.i,"thisRsltsAmt"));
        scwin.sellAmt5 = $c.num.parseInt(ds_master.getCellData(scwin.i,"befDiffer"));
        scwin.sellAmt6 = $c.num.parseInt(ds_master.getCellData(scwin.i,"thisDiffer"));
        scwin.sellAmt7 = $c.num.parseInt(ds_master.getCellData(scwin.i,"sumBfyyThisAmt"));
        scwin.sellAmt8 = $c.num.parseInt(ds_master.getCellData(scwin.i,"sumPlanAmt"));
        scwin.sellAmt9 = $c.num.parseInt(ds_master.getCellData(scwin.i,"sumRsltsAmt"));
        scwin.sellAmt10 = $c.num.parseInt(ds_master.getCellData(scwin.i,"sumBefDiffer"));
        scwin.sellAmt11 = $c.num.parseInt(ds_master.getCellData(scwin.i,"sumDiffer"));        
        if (scwin.mAcctcd=="9300001" || scwin.mAcctcd=="9300002" || scwin.mAcctcd == "9300003" || scwin.mAcctcd == "9300004"|| scwin.mAcctcd=="9300005" || scwin.mAcctcd == "9300006" ) {
            // 당월증감
            ds_master.setCellData(scwin.i,"befDiffer", scwin.sellAmt4 - scwin.sellAmt2);  // thisRsltsAmt - bfyyThisAmt
            ds_master.setCellData(scwin.i,"thisDiffer", scwin.sellAmt4 - scwin.sellAmt3); // thisRsltsAmt - thisPlanAmt
            // 누계증감
            ds_master.setCellData(scwin.i,"sumBefDiffer", scwin.sellAmt9 - scwin.sellAmt7); // sumRsltsAmt - sumBfyyThisAmt
            ds_master.setCellData(scwin.i,"sumDiffer", scwin.sellAmt9 - scwin.sellAmt8);    //  sumRsltsAmt - sumPlanAmt
        } else { 
            try { if (isNaN(scwin.sellAmt1)) { ds_master.setCellData(scwin.i,"yearPlanAmt", 0);  } else { ds_master.setCellData(scwin.i, "yearPlanAmt" , $c.num.round(scwin.sellAmt1/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"yearPlanAmt", 0);};
            try { if (isNaN(scwin.sellAmt2)) { ds_master.setCellData(scwin.i,"bfyyThisAmt", 0);  } else { ds_master.setCellData(scwin.i, "bfyyThisAmt" , $c.num.round(scwin.sellAmt2/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"bfyyThisAmt", 0); };
            try { if (isNaN(scwin.sellAmt3)) { ds_master.setCellData(scwin.i,"thisPlanAmt", 0);  } else { ds_master.setCellData(scwin.i, "thisPlanAmt" , $c.num.round(scwin.sellAmt3/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"thisPlanAmt", 0); };
            try { if (isNaN(scwin.sellAmt4)) { ds_master.setCellData(scwin.i,"thisRsltsAmt", 0);  } else { ds_master.setCellData(scwin.i, "thisRsltsAmt", $c.num.round(scwin.sellAmt4/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"thisRsltsAmt", 0); };
            try { if (isNaN(scwin.sellAmt7)) { ds_master.setCellData(scwin.i,"sumBfyyThisAmt", 0);} else { ds_master.setCellData(scwin.i, "sumBfyyThisAmt", $c.num.round(scwin.sellAmt7/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"sumBfyyThisAmt", 0); };
            try { if (isNaN(scwin.sellAmt8)) { ds_master.setCellData(scwin.i,"sumPlanAmt", 0);    } else { ds_master.setCellData(scwin.i, "sumPlanAmt" , $c.num.round(scwin.sellAmt8/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"sumPlanAmt", 0); };
            try { if (isNaN(scwin.sellAmt9)) { ds_master.setCellData(scwin.i,"sumRsltsAmt", 0);   } else {  ds_master.setCellData(scwin.i, "sumRsltsAmt", $c.num.round(scwin.sellAmt9/scwin.cunit,0)); }}  catch(e) {  ds_master.setCellData(scwin.i,"sumRsltsAmt", 0); };
           // 당월증감
            ds_master.setCellData(scwin.i,"befDiffer", $c.num.round(scwin.sellAmt4/scwin.cunit,0) - $c.num.round(scwin.sellAmt2/scwin.cunit,0));  // thisRsltsAmt - bfyyThisAmt
            ds_master.setCellData(scwin.i,"thisDiffer", $c.num.round(scwin.sellAmt4/scwin.cunit,0) - $c.num.round(scwin.sellAmt3/scwin.cunit,0));  // thisRsltsAmt - thisPlanAmt
            // 누계증감
            ds_master.setCellData(scwin.i,"sumBefDiffer", $c.num.round(scwin.sellAmt9/scwin.cunit,0) - $c.num.round(scwin.sellAmt7/scwin.cunit,0)); // sumRsltsAmt - sumBfyyThisAmt
            ds_master.setCellData(scwin.i,"sumDiffer", $c.num.round(scwin.sellAmt9/scwin.cunit,0) - $c.num.round(scwin.sellAmt8/scwin.cunit,0)); // sumRsltsAmt - sumPlanAmt
       }
    }
}

//-------------------------------------------------------------------------
// 금액을 재설정한다.
//-------------------------------------------------------------------------
