//-----------------------------------------------------------------------------
//    W E B S Q U A R E   C O M P O N E N T' S   E V E N T S
//------------------------------------------------------------------------------

scwin.btn_search_onclick = function () {
    let ret = $c.gus.cfValidate([ed_srchCloseYm,lc_version,lc_srchBookClsCd,lc_unit]); 
    if(!ret) {
        $c.win.alert("필수입력항목을 입력하세요!");
        return;
    }       
    scwin.f_Retrieve();
};

scwin.sbm_master_submiterror = function (e) {
    $c.gus.cfShowError(tr_search);
};

scwin.ds_version_ondataload = function () {
   scwin.f_SetFinalVer();
};

scwin.ed_srchCloseYm_onblur = function (e) {
     scwin.f_GetVersion();
};

scwin.ds_master_ondataload = function (e) {
    var rowCnt = ds_master.getTotalRow();
    totalRows.setValue(rowCnt);    

	if( rowCnt == 0 ){
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	} 

    if (rowCnt > 0) {
        ds_master.sort("prtPosSeq", 0); 

        scwin.f_Rate();     
        scwin.f_SetGridUnit();

        gr_master.setFocusedCell(0, 0);
    } 
}

scwin.sbm_closeYm_submitdone = function (e) {
    scwin.pcloseYm = ed_srchCloseYm.setValue(ds_closeYm.getCellData(0,"col1"));  
    if (scwin.pcloseYm == "") {ed_srchCloseYm.setValue(WebSquare.date.getCurrentServerDate("yyyyMM"));}
};

scwin.chk_distYn_onlabelclick = function (index, checked, value) {
    if (checked) { scwin.tDist = 1;} else { scwin.tDist = 0;};
};

scwin.lc_unit_onselected = function () {
   scwin.f_Retrieve();
};

scwin.ds_closeYm_ondataload = function () {
    if (ds_closeYm.getRowCount() > 0) {
        scwin.tcloseYm = ds_closeYm.getCellData(0,"col1");  
        ed_srchCloseYm.setValue(scwin.tcloseYm);
        scwin.f_SetGridFormat(scwin.tcloseYm);        
    } else {    
        if (scwin.tcloseYm == "") {ed_srchCloseYm.setValue(scwin.fromDate_YyMm);}
    } 
};

scwin.btn_Clear_onclick = function (e) {
    scwin.f_FieldClear();
};
